<!doctype html>
<html lang="it">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1">
<title>Questionario Preventivo Sito - Farmacia Corsetti</title>
<style>
:root{--primary:#6f98f5;--primary-dark:#3d68d8;--ink:#172033;--muted:#667085;--bg:#f5f7fb;--card:#fff;--border:#d9e0ef;--success:#11845b;--danger:#b42318;--radius:18px}*{box-sizing:border-box}body{margin:0;font-family:system-ui,-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif;color:var(--ink);background:radial-gradient(circle at top left,rgba(111,152,245,.22),transparent 32rem),var(--bg);line-height:1.5}.wrap{max-width:1040px;margin:0 auto;padding:20px}header{display:flex;align-items:center;justify-content:space-between;gap:18px;padding:18px 0 26px;flex-wrap:wrap}.brand img{width:min(300px,72vw);height:auto;display:block;background:#000;border-radius:14px;padding:12px}.badge{background:#eaf0ff;color:#2b52b7;padding:8px 12px;border-radius:999px;font-weight:700;font-size:.9rem;white-space:nowrap}.hero{background:linear-gradient(135deg,#fff,#edf3ff);border:1px solid var(--border);border-radius:var(--radius);padding:26px;box-shadow:0 18px 50px rgba(32,54,105,.09);margin-bottom:18px}.hero h1{margin:0 0 8px;font-size:clamp(1.7rem,4vw,3rem);line-height:1.05}.hero p{margin:0;color:var(--muted);font-size:1.05rem;max-width:760px}form{display:grid;gap:18px}.card{background:var(--card);border:1px solid var(--border);border-radius:var(--radius);padding:20px;box-shadow:0 10px 30px rgba(32,54,105,.06)}.card h2{margin:0 0 6px;font-size:1.25rem}.hint{color:var(--muted);margin:0 0 14px;font-size:.95rem}.grid{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:14px}label{display:block;font-weight:750;margin-bottom:7px}input,textarea,select{width:100%;min-height:48px;border:1px solid var(--border);border-radius:13px;padding:12px 13px;font-size:16px;background:#fff;color:var(--ink)}textarea{min-height:110px;resize:vertical}input:focus,textarea:focus,select:focus{outline:3px solid rgba(111,152,245,.28);border-color:var(--primary)}.home-list{display:grid;gap:10px}.home-row{display:grid;grid-template-columns:auto 1fr auto auto auto;gap:10px;align-items:center;border:1px solid var(--border);border-radius:14px;padding:10px;background:#fbfcff}.home-row input[type=checkbox]{width:22px;min-height:22px;accent-color:var(--primary-dark)}.home-row input[type=text]{min-height:44px}.icon-btn{width:44px;height:44px;min-height:44px;padding:0;display:inline-flex;align-items:center;justify-content:center;border-radius:12px;box-shadow:none;background:#eef2ff;color:#294bb1;border:1px solid #cdd8ff;font-size:1rem;cursor:pointer}.icon-btn.danger{background:#fff1f0;color:var(--danger);border-color:#ffd1cc}.event-card{border:1px dashed #b9c6e4;border-radius:16px;padding:16px;margin-top:12px;background:#fbfcff}.event-card h3{margin:0 0 12px}.actions{display:flex;gap:10px;flex-wrap:wrap;margin-top:14px}button{border:0;border-radius:14px;min-height:48px;padding:12px 16px;font-weight:800;font-size:1rem;cursor:pointer;background:var(--primary-dark);color:#fff;box-shadow:0 10px 22px rgba(61,104,216,.22)}button.secondary{background:#eef2ff;color:#294bb1;box-shadow:none;border:1px solid #cdd8ff}button.danger{background:#fff1f0;color:var(--danger);border:1px solid #ffd1cc;box-shadow:none}button:disabled{opacity:.65;cursor:not-allowed}.qrbox{display:flex;align-items:center;gap:18px;flex-wrap:wrap;background:#fff;border:1px solid var(--border);border-radius:var(--radius);padding:18px;margin-bottom:18px}#qrcode{background:#fff;padding:10px;border-radius:14px;border:1px solid var(--border)}.status{display:none;padding:13px 14px;border-radius:14px;font-weight:750;margin-top:14px}.status.ok{display:block;background:#ecfdf3;color:var(--success);border:1px solid #abefc6}.status.err{display:block;background:#fff1f0;color:var(--danger);border:1px solid #fecdca}.small{color:var(--muted);font-size:.9rem}@media(max-width:720px){.wrap{padding:14px}.hero,.card{padding:16px}.grid{grid-template-columns:1fr}.actions button{width:100%}.home-row{grid-template-columns:auto 1fr auto auto auto;gap:6px;padding:8px}.icon-btn{width:38px;height:38px;min-height:38px}}
</style>
</head>
<body>
<div class="wrap">
<header><div class="brand"><img src="corsetti-logo.png" alt="Farmacia Corsetti"></div><span class="badge">Questionario preventivo sito</span></header>
<section class="hero"><h1>Raccolta informazioni per il nuovo sito</h1><p>Compilate le sezioni principali, aggiungete uno o piu eventi di prova e salvate le risposte. I dati verranno registrati nel Google Sheet collegato.</p></section>
<section class="qrbox"><div id="qrcode" aria-label="QR code pagina"></div><div><h2>Accesso rapido da cellulare</h2><p class="hint">Il QR code contiene automaticamente il link pubblico della pagina.</p><p class="small" id="pageUrl"></p></div></section>
<form id="siteForm">
<section class="card"><h2>Dati referente</h2><p class="hint">Informazione utile per identificare chi ha compilato il questionario.</p><label for="nomeCliente">Nome referente *</label><input id="nomeCliente" required placeholder="Nome e cognome"></section>
<section class="card"><h2>Home Page</h2><p class="hint">Modificate, aggiungete, cancellate o ordinate le sezioni della home page. Le sezioni spuntate verranno considerate attive.</p><div class="home-list" id="homeSections"></div><div class="actions"><button type="button" class="secondary" onclick="addHomeSection('',true)">+ Aggiungi sezione</button></div></section>
<section class="card"><h2>Eventi di prova</h2><p class="hint">Create eventi facsimile da mostrare nella pagina Eventi e, se desiderato, in Home.</p><div id="events"></div><div class="actions"><button type="button" class="secondary" onclick="addEvent()">+ Aggiungi evento</button></div></section>
<section class="card"><h2>Note</h2><label for="note">Indicazioni aggiuntive</label><textarea id="note" placeholder="Scrivete qui ulteriori note, preferenze o vincoli"></textarea><div class="actions"><button type="submit" id="sendBtn">Salva</button></div><div id="status" class="status"></div></section>
</form>
</div>
<script src="https://cdn.jsdelivr.net/npm/qrcodejs@1.0.0/qrcode.min.js"></script>
<script>
const WEB_APP_URL='https://script.google.com/macros/s/AKfycbx1BAoOWMTxiy6ln9haghpOsHlCctr0HUKDZcE1jtI6-kGmfVQiulnY5QNp6z6LmKJSVg/exec';let eventCounter=0;const DEFAULT_HOME_SECTIONS=['Telemedicina','Analisi e diagnostica','Corsetti Luxury','Eventi in evidenza','Campagne promo attive o in evidenza'];
function initQr(){const url=window.location.href;document.getElementById('pageUrl').textContent=url;const target=document.getElementById('qrcode');target.innerHTML='';new QRCode(target,{text:url,width:136,height:136,correctLevel:QRCode.CorrectLevel.H})}
function escapeHtml(v){return String(v||'').replaceAll('&','&amp;').replaceAll('"','&quot;').replaceAll('<','&lt;').replaceAll('>','&gt;')}
function trashIcon(){return '<svg width="19" height="19" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M3 6h18"></path><path d="M8 6V4h8v2"></path><path d="M19 6l-1 14H6L5 6"></path><path d="M10 11v6"></path><path d="M14 11v6"></path></svg>'}
function addHomeSection(text='',checked=true){const row=document.createElement('div');row.className='home-row';row.innerHTML=`<input type="checkbox" class="home-active" ${checked?'checked':''} aria-label="Sezione attiva"><input type="text" class="home-title" value="${escapeHtml(text)}" placeholder="Nome sezione home page"><button type="button" class="icon-btn" title="Sposta su" onclick="moveHomeUp(this)">↑</button><button type="button" class="icon-btn" title="Sposta giu" onclick="moveHomeDown(this)">↓</button><button type="button" class="icon-btn danger" title="Elimina sezione" onclick="this.closest('.home-row').remove();saveDraft();">${trashIcon()}</button>`;document.getElementById('homeSections').appendChild(row);saveDraft()}
function moveHomeUp(btn){const row=btn.closest('.home-row');const prev=row.previousElementSibling;if(prev)row.parentElement.insertBefore(row,prev);saveDraft()}
function moveHomeDown(btn){const row=btn.closest('.home-row');const next=row.nextElementSibling;if(next)row.parentElement.insertBefore(next,row);saveDraft()}
function getHomeSections(){return [...document.querySelectorAll('.home-row')].map((row,index)=>({numero:index+1,attiva:row.querySelector('.home-active').checked,nome:row.querySelector('.home-title').value.trim()})).filter(s=>s.nome)}
function addEvent(data={}){eventCounter++;const div=document.createElement('div');div.className='event-card';div.innerHTML=`<h3>Evento ${eventCounter}</h3><div class="grid"><div><label>Nome evento *</label><input class="ev-nome" required value="${escapeHtml(data.nome||'')}" placeholder="Es. Open day telemedicina"></div><div><label>Data evento</label><input class="ev-data" type="date" value="${escapeHtml(data.data||'')}"></div><div><label>Luogo evento</label><select class="ev-luogo"><option ${data.luogo==='EUR'?'selected':''}>EUR</option><option ${data.luogo==='Vigna Clara'?'selected':''}>Vigna Clara</option></select></div><div><label>In evidenza</label><select class="ev-evidenza"><option value="Si" ${data.inEvidenza==='Si'?'selected':''}>Si</option><option value="No" ${data.inEvidenza==='No'?'selected':''}>No</option></select></div><div><label>Richiesta prenotazione</label><select class="ev-prenotazione"><option value="No" ${data.prenotazione==='No'?'selected':''}>No</option><option value="Si" ${data.prenotazione==='Si'?'selected':''}>Si</option></select></div><div><label>Link prenotazione</label><input class="ev-link" type="url" value="${escapeHtml(data.link||'')}" placeholder="https://..."></div></div><label style="margin-top:12px;">Descrizione evento</label><textarea class="ev-desc" placeholder="Descrizione sintetica dell'evento">${escapeHtml(data.descrizione||'')}</textarea><div class="actions"><button type="button" class="danger" onclick="this.closest('.event-card').remove();saveDraft();">Rimuovi evento</button></div>`;document.getElementById('events').appendChild(div);saveDraft()}
function getEvents(){return [...document.querySelectorAll('.event-card')].map((card,index)=>({numero:index+1,nome:card.querySelector('.ev-nome').value.trim(),data:card.querySelector('.ev-data').value,luogo:card.querySelector('.ev-luogo').value,inEvidenza:card.querySelector('.ev-evidenza').value,descrizione:card.querySelector('.ev-desc').value.trim(),prenotazione:card.querySelector('.ev-prenotazione').value,link:card.querySelector('.ev-link').value.trim()}))}
function collectData(){const homeSections=getHomeSections();return{timestampPagina:new Date().toISOString(),pagina:window.location.href,nomeCliente:document.getElementById('nomeCliente').value.trim(),emailCliente:'',sezioniHome:homeSections,temiHome:homeSections.filter(s=>s.attiva).map(s=>s.nome),altriTemi:'',menu:[],eventi:getEvents(),note:document.getElementById('note').value.trim()}}
function showStatus(message,ok=true){const el=document.getElementById('status');el.className='status '+(ok?'ok':'err');el.textContent=message}

async function submitToGoogleSheet(data){
    const res = await fetch('https://corsetti.store360.it/salva-menu.php',{
        method:'POST',
        headers:{'Content-Type':'application/json'},
        body:JSON.stringify(data)
    });
    if(!res.ok) throw new Error('Errore server');
    return res.json();
}
  
document.getElementById('siteForm').addEventListener('submit',async(e)=>{e.preventDefault();const form=e.currentTarget;if(!form.checkValidity()){form.reportValidity();return}const data=collectData();const btn=document.getElementById('sendBtn');btn.disabled=true;btn.textContent='Salvataggio...';try{await submitToGoogleSheet(data);showStatus('Risposte salvate correttamente.',true);localStorage.removeItem('corsettiQuestionarioDraft')}catch(err){showStatus('Salvataggio non riuscito. Controlla connessione o URL Apps Script.',false)}finally{btn.disabled=false;btn.textContent='Salva'}});
function saveDraft(){try{localStorage.setItem('corsettiQuestionarioDraft',JSON.stringify(collectData()))}catch(e){}}
function loadDraft(){try{const raw=localStorage.getItem('corsettiQuestionarioDraft');if(!raw)return false;const data=JSON.parse(raw);document.getElementById('nomeCliente').value=data.nomeCliente||'';document.getElementById('homeSections').innerHTML='';if(Array.isArray(data.sezioniHome)&&data.sezioniHome.length){data.sezioniHome.forEach(s=>addHomeSection(s.nome,s.attiva))}else{DEFAULT_HOME_SECTIONS.forEach(name=>addHomeSection(name,true))}document.getElementById('events').innerHTML='';(data.eventi||[]).forEach(addEvent);if(!data.eventi||!data.eventi.length)addEvent();document.getElementById('note').value=data.note||'';return true}catch(e){return false}}
async function loadFromServer(){try{const res=await fetch('/menu.json?t='+Date.now());if(!res.ok)return false;const data=await res.json();if(!Array.isArray(data)||!data.length)return false;document.getElementById('homeSections').innerHTML='';data.forEach(v=>addHomeSection(v.label,v.attiva));return true}catch(e){return false}}
document.addEventListener('input',()=>saveDraft());document.addEventListener('change',()=>saveDraft());window.addEventListener('load',async()=>{initQr();const loaded=await loadFromServer();if(!loaded){if(!loadDraft()){DEFAULT_HOME_SECTIONS.forEach(name=>addHomeSection(name,true));addEvent()}}else{const raw=localStorage.getItem('corsettiQuestionarioDraft');if(raw){try{const data=JSON.parse(raw);document.getElementById('nomeCliente').value=data.nomeCliente||'';document.getElementById('events').innerHTML='';(data.eventi||[]).forEach(addEvent);if(!data.eventi||!data.eventi.length)addEvent();document.getElementById('note').value=data.note||'';}catch(e){addEvent();}}else{addEvent();}}});
</script>
</body>
</html>
